from math import gcd
class Solution:
    def gcdValues(self, nums, queries):
        n = len(nums)
        pairs = []
        for i in range(n):
            for j in range(i + 1, n):
                pairs.append(gcd(nums[i], nums[j]))
        pairs.sort()
        return [pairs[q] for q in queries]

