class Solution:
    def gcdValues(self, nums, queries):
        maxV = max(nums)
        cnt = [0] * (maxV + 1)
        for v in nums:
            cnt[v] += 1
        divCount = [0] * (maxV + 1)
        for d in range(1, maxV + 1):
            s = 0
            for m in range(d, maxV + 1, d):
                s += cnt[m]
            divCount[d] = s
        exact = [0] * (maxV + 2)
        for d in range(maxV, 0, -1):
            c = divCount[d]
            pairs = c * (c - 1) // 2
            m2 = 2 * d
            while m2 <= maxV:
                pairs -= exact[m2]
                m2 += d
            exact[d] = pairs
        prefix = [0] * (maxV + 1)
        run = 0
        for d in range(1, maxV + 1):
            run += exact[d]
            prefix[d] = run
        ans = []
        for q in queries:
            lo, hi = 1, maxV
            while lo < hi:
                mid = (lo + hi) // 2
                if prefix[mid] > q:
                    hi = mid
                else:
                    lo = mid + 1
            ans.append(lo)
        return ans

