var gcdValues = function(nums, queries) {
    const maxV = Math.max(...nums);
    const cnt = new Array(maxV + 1).fill(0);
    for (const v of nums) cnt[v]++;
    const divCount = new Array(maxV + 1).fill(0);
    for (let d = 1; d <= maxV; d++) {
        let s = 0;
        for (let m = d; m <= maxV; m += d) s += cnt[m];
        divCount[d] = s;
    }
    const exact = new Array(maxV + 2).fill(0);
    for (let d = maxV; d >= 1; d--) {
        const c = divCount[d];
        let pairs = c * (c - 1) / 2;
        for (let m2 = 2 * d; m2 <= maxV; m2 += d) pairs -= exact[m2];
        exact[d] = pairs;
    }
    const prefix = new Array(maxV + 1).fill(0);
    let run = 0;
    for (let d = 1; d <= maxV; d++) {
        run += exact[d];
        prefix[d] = run;
    }
    const ans = [];
    for (const q of queries) {
        let lo = 1, hi = maxV;
        while (lo < hi) {
            const mid = Math.floor((lo + hi) / 2);
            if (prefix[mid] > q) hi = mid; else lo = mid + 1;
        }
        ans.push(lo);
    }
    return ans;
};
